registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLength: 48,
    lastX: g.px,
    lastY: g.py
  };

  var trail = g._trail;
  var ctx = g.ctx;
  var dx = g.px - trail.lastX;
  var dy = g.py - trail.lastY;
  var moved = dx * dx + dy * dy > 0.1;

  if (moved) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLength) {
      trail.points.shift();
    }
    trail.lastX = g.px;
    trail.lastY = g.py;
  }

  var len = trail.points.length;
  if (len < 2) return;

  for (var i = 1; i < len; i++) {
    var pt = trail.points[i];
    var prev = trail.points[i - 1];
    var t = i / len;
    var alpha = t * t * 0.85;
    var size = t * 2.8 + 0.4;

    var r = Math.round(g.lerp(0, 0, t));
    var green = Math.round(g.lerp(180, 255, t));
    var b = Math.round(g.lerp(120, 170, t));

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.strokeStyle = 'rgba(' + r + ',' + green + ',' + b + ',1)';
    ctx.lineWidth = size;
    ctx.lineCap = 'round';
    ctx.shadowColor = '#00ffaa';
    ctx.shadowBlur = Math.round(t * 8);
    ctx.beginPath();
    ctx.moveTo(prev.x, prev.y);
    ctx.lineTo(pt.x, pt.y);
    ctx.stroke();
    ctx.restore();
  }

  // Glow dot at trail head (oldest visible)
  var head = trail.points[0];
  ctx.save();
  ctx.globalAlpha = 0.18;
  ctx.fillStyle = '#00ffaa';
  ctx.shadowColor = '#00ffaa';
  ctx.shadowBlur = 6;
  ctx.beginPath();
  ctx.arc(head.x, head.y, 1.2, 0, Math.PI * 2);
  ctx.fill();
  ctx.restore();

  // Decay trail when not moving
  if (!moved && trail.points.length > 0) {
    if (g.tick % 3 === 0) {
      trail.points.shift();
    }
  }
})

