registerModule('Ambient Starfield', function(g) {
  g._stars = g._stars || (function() {
    var arr = [];
    for (var i = 0; i < 200; i++) {
      arr.push({
        x: Math.random() * 1600,
        y: Math.random() * 1200,
        z: Math.random(),
        speed: 0.05 + Math.random() * 0.2,
        size: 0.4 + Math.random() * 1.2,
        phase: Math.random() * Math.PI * 2,
        hue: Math.random() < 0.15 ? (180 + Math.random() * 60 | 0) : 220
      });
    }
    return arr;
  })();

  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var stars = g._stars;
  var t = g.tick * 0.01;

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Drift slowly, parallax with player velocity
    s.x -= g.vx * s.z * 0.4 + s.speed * 0.3;
    s.y -= g.vy * s.z * 0.4;

    // Wrap around canvas bounds with some padding
    if (s.x < -10) s.x = W + 10;
    if (s.x > W + 10) s.x = -10;
    if (s.y < -10) s.y = H + 10;
    if (s.y > H + 10) s.y = -10;

    // Twinkle
    var twinkle = 0.5 + 0.5 * Math.sin(t * 2.3 + s.phase);
    var alpha = (0.3 + 0.55 * s.z) * (0.7 + 0.3 * twinkle);

    var sz = s.size * (0.8 + 0.4 * twinkle);

    ctx.globalAlpha = alpha;

    if (s.z > 0.75 && sz > 1.0) {
      // Brighter stars get a soft glow
      var grd = ctx.createRadialGradient(s.x, s.y, 0, s.x, s.y, sz * 3);
      grd.addColorStop(0, 'hsla(' + s.hue + ',80%,95%,1)');
      grd.addColorStop(1, 'hsla(' + s.hue + ',60%,70%,0)');
      ctx.fillStyle = grd;
      ctx.beginPath();
      ctx.arc(s.x, s.y, sz * 3, 0, Math.PI * 2);
      ctx.fill();
    }

    // Core dot
    ctx.fillStyle = 'hsl(' + s.hue + ',50%,' + (70 + s.z * 25 | 0) + '%)';
    ctx.globalAlpha = alpha;
    ctx.beginPath();
    ctx.arc(s.x, s.y, sz, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 1;
})
